from collections import defaultdict

def solve(points: list[list[int]]) -> int:
    n = len(points)
    count = 0
    # Dictionary to store the slope between pairs of points
    slope_dict = defaultdict(list)

    # Iterate over all pairs of points
    for i in range(n):
        x1, y1 = points[i]
        for j in range(i + 1, n):
            x2, y2 = points[j]
            # Calculate the slope between points i and j
            if x1 == x2:
                slope = float('inf')  # vertical line
            else:
                slope = (y2 - y1) / (x2 - x1)
            # Store the indices of the points with this slope
            slope_dict[slope].append((i, j))

    # Iterate over all pairs of slopes
    for slope1 in slope_dict:
        for slope2 in slope_dict:
            # If the slopes are the same, skip to avoid counting the same pair twice
            if slope1 == slope2:
                continue
            # Get the list of point pairs for each slope
            pairs1 = slope_dict[slope1]
            pairs2 = slope_dict[slope2]
            # Count the number of combinations of two pairs that form a trapezoid
            # Each pair of pairs forms a trapezoid if they share a common point
            for p1 in pairs1:
                for p2 in pairs2:
                    if p1[0] in p2 or p1[1] in p2:
                        count += 1

    return count // 2
